function getWordsByRoot(root){return WORD_DATA.filter(w=>w.root===root);}
function getAllRoots(){return Object.keys(ROOT_DATA);}
function getRandomWords(count){const shuffled=[...WORD_DATA].sort(()=>0.5-Math.random());return shuffled.slice(0,count);}
function getWord(word){return WORD_DATA.find(w=>w.word===word);}

if(typeof module!=='undefined'&&module.exports){module.exports={ROOT_DATA,WORD_DATA,getWordsByRoot,getAllRoots,getRandomWords,getWord};}
